 334→/// Tally - add a new Tack to a Pace
 335→///
 336→/// Prepends a new Tack with state transition and/or plan refinement.
 337→pub fn jjrg_tally(gallops: &mut jjrg_Gallops, args: jjrg_TallyArgs) -> Result<(), String> {
 338→    // Parse and normalize coronet
 339→    let coronet = Coronet::jjrf_parse(&args.coronet)
 340→        .map_err(|e| format!("Invalid coronet: {}", e))?;
 341→    let coronet_key = coronet.jjrf_display();
 342→
 343→    // Extract parent Firemark
 344→    let firemark = coronet.jjrf_parent_firemark();
 345→    let firemark_key = firemark.jjrf_display();
 346→
 347→    // Verify Heat exists
 348→    let heat = gallops.heats.get_mut(&firemark_key)
 349→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
 350→
 351→    // Verify Pace exists
 352→    let pace = heat.paces.get_mut(&coronet_key)
 353→        .ok_or_else(|| format!("Pace '{}' not found", coronet_key))?;
 354→
 355→    // Read current Tack
 356→    let current_tack = pace.tacks.first()
 357→        .ok_or_else(|| "Pace has no tacks (should never happen)".to_string())?;
 358→
 359→    // Check for the new-spec-invalidates-bridled condition:
 360→    // If pace is currently bridled AND new spec text is provided AND no explicit --state,
 361→    // then auto-reset to rough (new spec invalidates old direction)
 362→    let auto_reset_to_rough = args.state.is_none()
 363→        && matches!(current_tack.state, jjrg_PaceState::Bridled)
 364→        && args.text.is_some();
 365→
 366→    // Determine new state
 367→    let new_state = if auto_reset_to_rough {
 368→        jjrg_PaceState::Rough
 369→    } else {
 370→        args.state.clone().unwrap_or_else(|| current_tack.state.clone())
 371→    };
 372→
 373→    // Determine new direction
 374→    let new_direction = match (&args.state, &new_state) {
 375→        // State explicitly set to bridled: direction required
 376→        (Some(jjrg_PaceState::Bridled), _) => {
 377→            match &args.direction {
 378→                Some(d) if !d.is_empty() => Some(d.clone()),
 379→                Some(_) => return Err("direction must not be empty when state is bridled".to_string()),
 380→                None => return Err("direction is required when state is bridled".to_string()),
 381→            }
 382→        }
 383→        // State explicitly set to something other than bridled: direction forbidden
 384→        (Some(_), _) => {
 385→            if args.direction.is_some() {
 386→                return Err("direction must be absent when state is not bridled".to_string());
 387→            }
 388→            None
 389→        }
 390→        // Auto-reset to rough: no direction
 391→        _ if auto_reset_to_rough => None,
 392→        // State inherited and was bridled: inherit direction
 393→        (None, jjrg_PaceState::Bridled) => {
 394→            args.direction.or_else(|| current_tack.direction.clone())
 395→        }
 396→        // State inherited and was not bridled: no direction
 397→        (None, _) => None,
 398→    };
 399→
 400→    // Determine new text
 401→    let new_text = args.text.unwrap_or_else(|| current_tack.text.clone());
 402→    if new_text.is_empty() {
 403→        return Err("text must not be empty".to_string());
 404→    }
 405→
 406→    // Determine new silks
 407→    let new_silks = args.silks.unwrap_or_else(|| current_tack.silks.clone());
 408→
 409→    // Create new Tack
 410→    let new_tack = jjrg_make_tack(
 411→        new_state,
 412→        new_text,
 413→        new_silks,
 414→        new_direction,
 415→    );
 416→
 417→    // Prepend to tacks array
 418→    pace.tacks.insert(0, new_tack);
 419→
 420→    Ok(())
 421→}
