 423→/// Draft - move a Pace from one Heat to another
 424→///
 425→/// Moves the pace to the destination heat with a new Coronet.
 426→/// All Tack history is preserved, with a new Tack recording the draft.
 427→/// State is NOT changed - draft is a move operation, not a state transition.
 428→pub fn jjrg_draft(gallops: &mut jjrg_Gallops, args: jjrg_DraftArgs) -> Result<jjrg_DraftResult, String> {
 429→    // Validate positioning mutual exclusivity
 430→    let position_count = [args.before.is_some(), args.after.is_some(), args.first]
 431→        .iter()
 432→        .filter(|&&x| x)
 433→        .count();
 434→    if position_count > 1 {
 435→        return Err("Only one of --before, --after, or --first may be specified".to_string());
 436→    }
 437→
 438→    // Parse and normalize source coronet
 439→    let source_coronet = Coronet::jjrf_parse(&args.coronet)
 440→        .map_err(|e| format!("Invalid coronet: {}", e))?;
 441→    let source_coronet_key = source_coronet.jjrf_display();
 442→
 443→    // Extract source Firemark from coronet
 444→    let source_firemark = source_coronet.jjrf_parent_firemark();
 445→    let source_firemark_key = source_firemark.jjrf_display();
 446→
 447→    // Parse and normalize destination firemark
 448→    let dest_firemark = Firemark::jjrf_parse(&args.to)
 449→        .map_err(|e| format!("Invalid destination firemark: {}", e))?;
 450→    let dest_firemark_key = dest_firemark.jjrf_display();
 451→
 452→    // Validate source and destination are different
 453→    if source_firemark_key == dest_firemark_key {
 454→        return Err("Cannot draft pace to same heat".to_string());
 455→    }
 456→
 457→    // Verify source heat exists
 458→    if !gallops.heats.contains_key(&source_firemark_key) {
 459→        return Err(format!("Source heat '{}' not found", source_firemark_key));
 460→    }
 461→
 462→    // Verify destination heat exists
 463→    if !gallops.heats.contains_key(&dest_firemark_key) {
 464→        return Err(format!("Heat '{}' not found", dest_firemark_key));
 465→    }
 466→
 467→    // Verify pace exists in source heat
 468→    {
 469→        let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
 470→        if !source_heat.paces.contains_key(&source_coronet_key) {
 471→            return Err(format!("Pace {} not found in heat {}", source_coronet_key, source_firemark_key));
 472→        }
 473→    }
 474→
 475→    // Validate positioning target if specified
 476→    let insert_position = if let Some(ref before_str) = args.before {
 477→        let target = Coronet::jjrf_parse(before_str)
 478→            .map_err(|e| format!("Invalid --before coronet: {}", e))?;
 479→        let target_key = target.jjrf_display();
 480→        let dest_heat = gallops.heats.get(&dest_firemark_key).unwrap();
 481→        let pos = dest_heat.order.iter().position(|c| c == &target_key)
 482→            .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
 483→        Some(pos)
 484→    } else if let Some(ref after_str) = args.after {
 485→        let target = Coronet::jjrf_parse(after_str)
 486→            .map_err(|e| format!("Invalid --after coronet: {}", e))?;
 487→        let target_key = target.jjrf_display();
 488→        let dest_heat = gallops.heats.get(&dest_firemark_key).unwrap();
 489→        let pos = dest_heat.order.iter().position(|c| c == &target_key)
 490→            .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
 491→        Some(pos + 1)
 492→    } else if args.first {
 493→        Some(0)
 494→    } else {
 495→        None // Append to end
 496→    };
 497→
 498→    // Remove pace from source heat
 499→    let source_heat = gallops.heats.get_mut(&source_firemark_key).unwrap();
 500→    let pace_data = source_heat.paces.remove(&source_coronet_key)
 501→        .ok_or_else(|| format!("Pace {} not found", source_coronet_key))?;
 502→    source_heat.order.retain(|c| c != &source_coronet_key);
 503→
 504→    // Get destination heat and allocate new coronet
 505→    let dest_heat = gallops.heats.get_mut(&dest_firemark_key).unwrap();
 506→    let new_coronet_str = format!("{}{}{}", CORONET_PREFIX, dest_firemark.jjrf_as_str(), dest_heat.next_pace_seed);
 507→
 508→    // Create new tack recording the draft
 509→    let first_tack = pace_data.tacks.first();
 510→    let draft_note = format!("Drafted from {} in {}.\n\n{}",
 511→        source_coronet_key, source_firemark_key,
 512→        first_tack.map(|t| t.text.as_str()).unwrap_or(""));
 513→
 514→    let draft_tack = jjrg_make_tack(
 515→        first_tack.map(|t| t.state.clone()).unwrap_or(jjrg_PaceState::Rough),
 516→        draft_note,
 517→        first_tack.map(|t| t.silks.clone()).unwrap_or_default(),
 518→        first_tack.and_then(|t| t.direction.clone()),
 519→    );
 520→
 521→    // Build new pace with draft tack prepended
 522→    let mut new_tacks = vec![draft_tack];
 523→    new_tacks.extend(pace_data.tacks);
 524→
 525→    let new_pace = jjrg_Pace {
 526→        tacks: new_tacks,
 527→    };
 528→
 529→    // Insert into destination heat
 530→    match insert_position {
 531→        Some(pos) => dest_heat.order.insert(pos, new_coronet_str.clone()),
 532→        None => dest_heat.order.push(new_coronet_str.clone()),
 533→    }
 534→    dest_heat.paces.insert(new_coronet_str.clone(), new_pace);
 535→
 536→    // Increment destination seed
 537→    dest_heat.next_pace_seed = zjjrg_increment_seed(&dest_heat.next_pace_seed);
 538→
 539→    Ok(jjrg_DraftResult { new_coronet: new_coronet_str })
 540→}
