 542→/// Retire a Heat
 543→///
 544→/// Creates trophy file, removes heat from gallops, deletes paddock file.
 545→/// Does NOT save gallops or commit - caller is responsible for that.
 546→pub fn jjrg_retire(
 547→    gallops: &mut jjrg_Gallops,
 548→    args: jjrg_RetireArgs,
 549→    base_path: &Path,
 550→    steeplechase: &[SteeplechaseEntry],
 551→) -> Result<jjrg_RetireResult, String> {
 552→    // Parse and normalize firemark
 553→    let firemark = Firemark::jjrf_parse(&args.firemark)
 554→        .map_err(|e| format!("Invalid firemark: {}", e))?;
 555→    let firemark_key = firemark.jjrf_display();
 556→
 557→    // Validate today is YYMMDD
 558→    if !zjjrg_is_yymmdd(&args.today) {
 559→        return Err(format!("today must be YYMMDD format, got '{}'", args.today));
 560→    }
 561→
 562→    // Verify heat exists
 563→    let heat = gallops.heats.get(&firemark_key)
 564→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
 565→
 566→    // Read paddock content before we remove anything
 567→    let paddock_path = base_path.join(&heat.paddock_file);
 568→    let paddock_content = fs::read_to_string(&paddock_path)
 569→        .map_err(|e| format!("Failed to read paddock file '{}': {}", heat.paddock_file, e))?;
 570→
 571→    // Build trophy content
 572→    let trophy_content = zjjrg_build_trophy_content(&firemark_key, heat, &paddock_content, &args.today, steeplechase)?;
 573→
 574→    // Compute trophy path: .claude/jjm/retired/jjh_b<created>-r<today>-<silks>.md
 575→    let trophy_filename = format!(
 576→        "jjh_b{}-r{}-{}.md",
 577→        heat.creation_time,
 578→        args.today,
 579→        heat.silks
 580→    );
 581→    let trophy_rel_path = format!(".claude/jjm/retired/{}", trophy_filename);
 582→    let trophy_full_path = base_path.join(&trophy_rel_path);
 583→
 584→    // Create retired directory if needed
 585→    if let Some(parent) = trophy_full_path.parent() {
 586→        fs::create_dir_all(parent)
 587→            .map_err(|e| format!("Failed to create retired directory: {}", e))?;
 588→    }
 589→
 590→    // Write trophy file
 591→    fs::write(&trophy_full_path, trophy_content)
 592→        .map_err(|e| format!("Failed to write trophy file: {}", e))?;
 593→
 594→    // Capture info for result before removing heat
 595→    let silks = heat.silks.clone();
 596→    let paddock_file = heat.paddock_file.clone();
 597→
 598→    // Remove heat from gallops (do NOT change next_heat_seed)
 599→    // Use shift_remove to preserve order of remaining heats
 600→    gallops.heats.shift_remove(&firemark_key);
 601→
 602→    // Delete paddock file
 603→    if paddock_path.exists() {
 604→        fs::remove_file(&paddock_path)
 605→            .map_err(|e| format!("Failed to delete paddock file: {}", e))?;
 606→    }
 607→
 608→    Ok(jjrg_RetireResult {
 609→        trophy_path: trophy_rel_path,
 610→        paddock_path: paddock_file,
 611→        silks,
 612→        firemark: firemark_key,
 613→    })
 614→}
