 637→
 638→/// Build trophy markdown content
 639→fn zjjrg_build_trophy_content(
 640→    firemark_key: &str,
 641→    heat: &jjrg_Heat,
 642→    paddock_content: &str,
 643→    today: &str,
 644→    steeplechase: &[SteeplechaseEntry],
 645→) -> Result<String, String> {
 646→    let mut content = String::new();
 647→
 648→    // Header
 649→    content.push_str(&format!("# Heat Trophy: {}\n\n", heat.silks));
 650→    content.push_str(&format!("**Firemark:** {}\n", firemark_key));
 651→    content.push_str(&format!("**Created:** {}\n", heat.creation_time));
 652→    content.push_str(&format!("**Retired:** {}\n", today));
 653→    content.push_str("**Status:** retired\n\n");
 654→
 655→    // Paddock
 656→    content.push_str("## Paddock\n\n");
 657→    content.push_str(paddock_content);
 658→    if !paddock_content.ends_with('\n') {
 659→        content.push('\n');
 660→    }
 661→    content.push('\n');
 662→
 663→    // Paces (in order)
 664→    content.push_str("## Paces\n\n");
 665→    for coronet_key in &heat.order {
 666→        if let Some(pace) = heat.paces.get(coronet_key) {
 667→            // Get final state from most recent tack
 668→            let final_state = pace.tacks.first()
 669→                .map(|t| match t.state {
 670→                    jjrg_PaceState::Rough => "rough",
 671→                    jjrg_PaceState::Bridled => "bridled",
 672→                    jjrg_PaceState::Complete => "complete",
 673→                    jjrg_PaceState::Abandoned => "abandoned",
 674→                })
 675→                .unwrap_or("unknown");
 676→
 677→            let pace_silks = pace.tacks.first()
 678→                .map(|t| t.silks.as_str())
 679→                .unwrap_or("unknown");
 680→
 681→            content.push_str(&format!(
 682→                "### {} ({}) [{}]\n\n",
 683→                pace_silks, coronet_key, final_state
 684→            ));
 685→
 686→            // Tack history (newest first, as stored)
 687→            for tack in &pace.tacks {
 688→                let state_str = match tack.state {
 689→                    jjrg_PaceState::Rough => "rough",
 690→                    jjrg_PaceState::Bridled => "bridled",
 691→                    jjrg_PaceState::Complete => "complete",
 692→                    jjrg_PaceState::Abandoned => "abandoned",
 693→                };
 694→                content.push_str(&format!("**[{}] {}**\n\n", tack.ts, state_str));
 695→                content.push_str(&tack.text);
 696→                if !tack.text.ends_with('\n') {
 697→                    content.push('\n');
 698→                }
 699→                if let Some(ref direction) = tack.direction {
 700→                    content.push_str(&format!("\n*Direction:* {}\n", direction));
 701→                }
 702→                content.push('\n');
 703→            }
 704→        }
 705→    }
 706→
 707→    // Commit Activity (bitmap views)
 708→    let firemark = Firemark::jjrf_parse(firemark_key)
 709→        .map_err(|e| format!("Invalid firemark in trophy builder: {}", e))?;
 710→    content.push_str("## Commit Activity\n\n");
 711→    content.push_str("```\n");
 712→    if let Ok(bitmap) = jjrpd_format_file_bitmap(&firemark, heat) {
 713→        content.push_str(&bitmap);
 714→    }
 715→    if let Ok(swimlanes) = jjrpd_format_commit_swimlanes(&firemark, heat) {
 716→        content.push_str(&swimlanes);
 717→    }
 718→    content.push_str("```\n\n");
 719→
 720→    // Steeplechase (newest first, as provided)
 721→    content.push_str("## Steeplechase\n\n");
 722→    if steeplechase.is_empty() {
 723→        content.push_str("(no entries)\n\n");
 724→    } else {
 725→        for entry in steeplechase {
 726→            // Format: ### {date} - {coronet or "Heat"} - {action or "notch"}
 727→            let identity = entry.coronet.as_deref().unwrap_or("Heat");
 728→            let action = entry.action.as_deref().unwrap_or("notch");
 729→            content.push_str(&format!(
 730→                "### {} - {} - {}\n\n",
 731→                entry.timestamp, identity, action
 732→            ));
 733→            content.push_str(&entry.subject);
 734→            if !entry.subject.ends_with('\n') {
 735→                content.push('\n');
 736→            }
 737→            content.push('\n');
 738→        }
 739→    }
 740→
 741→    Ok(content)
 742→}
