 744→/// Curry - update Heat paddock with chalk entry
 745→///
 746→/// Writes new paddock content and creates a chalk commit recording the change.
 747→pub fn jjrg_curry(
 748→    gallops_path: &std::path::Path,
 749→    firemark: &Firemark,
 750→    new_content: &str,
 751→    note: Option<&str>,
 752→) -> Result<(), String> {
 753→    use std::fs;
 754→
 755→    // Load gallops
 756→    let gallops = jjrg_Gallops::jjrg_load(gallops_path)
 757→        .map_err(|e| format!("Failed to load Gallops: {}", e))?;
 758→
 759→    // Verify heat exists
 760→    let firemark_key = firemark.jjrf_display();
 761→    let heat = gallops.heats.get(&firemark_key)
 762→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
 763→
 764→    // Write new paddock content
 765→    let paddock_path = std::path::Path::new(&heat.paddock_file);
 766→    fs::write(paddock_path, new_content)
 767→        .map_err(|e| format!("Failed to write paddock file: {}", e))?;
 768→
 769→    // Build chalk message
 770→    let description = if let Some(n) = note {
 771→        format!("paddock curried: {}", n)
 772→    } else {
 773→        "paddock curried".to_string()
 774→    };
 775→
 776→    // Create chalk commit using vvc
 777→    use crate::jjrn_notch::jjrn_format_heat_discussion;
 778→    let message = jjrn_format_heat_discussion(firemark, &description);
 779→
 780→    let commit_args = vvc::vvcm_CommitArgs {
 781→        files: vec![paddock_path.to_string_lossy().to_string()],
 782→        message,
 783→        size_limit: vvc::VVCG_SIZE_LIMIT,
 784→        warn_limit: vvc::VVCG_WARN_LIMIT,
 785→    };
 786→
 787→    // Acquire lock for commit
 788→    let lock = vvc::vvcc_CommitLock::vvcc_acquire()
 789→        .map_err(|e| format!("Failed to acquire commit lock: {}", e))?;
 790→
 791→    match vvc::machine_commit(&lock, &commit_args) {
 792→        Ok(hash) => {
 793→            eprintln!("jjx_curry: committed {}", &hash[..8]);
 794→            Ok(())
 795→        }
 796→        Err(e) => Err(format!("Commit failed: {}", e)),
 797→    }
 798→    // lock released here
 799→}
