 801→/// Furlough a Heat - change status or rename
 802→///
 803→/// Updates heat status (racing/stabled) and/or silks.
 804→/// At least one change must be requested.
 805→pub fn jjrg_furlough(gallops: &mut jjrg_Gallops, args: jjrg_FurloughArgs) -> Result<(), String> {
 806→    // Validate at least one option provided
 807→    if !args.racing && !args.stabled && args.silks.is_none() {
 808→        return Err("At least one option required: --racing, --stabled, or --silks".to_string());
 809→    }
 810→
 811→    // Validate racing/stabled mutual exclusivity
 812→    if args.racing && args.stabled {
 813→        return Err("Cannot specify both --racing and --stabled".to_string());
 814→    }
 815→
 816→    // Validate silks if provided
 817→    if let Some(ref silks) = args.silks {
 818→        if !zjjrg_is_kebab_case(silks) {
 819→            return Err(format!("silks must be non-empty alphanumeric-kebab (letters, digits, hyphens), got '{}'", silks));
 820→        }
 821→    }
 822→
 823→    // Parse and normalize firemark
 824→    let firemark = Firemark::jjrf_parse(&args.firemark)
 825→        .map_err(|e| format!("Invalid firemark: {}", e))?;
 826→    let firemark_key = firemark.jjrf_display();
 827→
 828→    // Verify Heat exists and check status
 829→    {
 830→        let heat = gallops.heats.get(&firemark_key)
 831→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
 832→
 833→        // Check not retired (terminal state)
 834→        if heat.status == jjrg_HeatStatus::Retired {
 835→            return Err(format!("Heat '{}' is retired (terminal state)", firemark_key));
 836→        }
 837→
 838→        // Note: requesting the same status is allowed — it promotes the heat
 839→        // to the top of its list (racing or stabled) for reordering purposes.
 840→    }
 841→
 842→    // Apply status change if requested — also promotes heat to top of list
 843→    if args.racing {
 844→        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Racing;
 845→        if let Some(heat_entry) = gallops.heats.shift_remove(&firemark_key) {
 846→            gallops.heats.shift_insert(0, firemark_key.clone(), heat_entry);
 847→        }
 848→    } else if args.stabled {
 849→        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Stabled;
 850→        if let Some(heat_entry) = gallops.heats.shift_remove(&firemark_key) {
 851→            gallops.heats.shift_insert(0, firemark_key.clone(), heat_entry);
 852→        }
 853→    }
 854→
 855→    // Apply silks change if requested
 856→    if let Some(silks) = args.silks {
 857→        gallops.heats.get_mut(&firemark_key).unwrap().silks = silks;
 858→    }
 859→
 860→    Ok(())
 861→}
 862→
 863→/// Garland a Heat - celebrate completion and create continuation
 864→///
 865→/// Updates source heat silks to garlanded form and status to stabled.
 866→/// Creates new heat with continuation silks, status racing.
 867→/// Transfers actionable paces (rough/bridled) to new heat.
 868→/// Retains complete/abandoned paces in garlanded heat.
 869→pub fn jjrg_garland(gallops: &mut jjrg_Gallops, args: jjrg_GarlandArgs, base_path: &Path) -> Result<jjrg_GarlandResult, String> {
 870→    use crate::jjrc_core::jjrc_timestamp_from_env;
 871→    use crate::jjrq_query::{jjrq_parse_silks_sequence, jjrq_build_garlanded_silks, jjrq_build_continuation_silks};
 872→
 873→    // Parse and normalize firemark
 874→    let firemark = Firemark::jjrf_parse(&args.firemark)
 875→        .map_err(|e| format!("Invalid firemark: {}", e))?;
 876→    let firemark_key = firemark.jjrf_display();
 877→
 878→    // Verify source heat exists and extract needed data (avoid holding the borrow)
 879→    let (source_silks, source_paddock_file, source_order, actionable_count, retained_count) = {
 880→        let source_heat = gallops.heats.get(&firemark_key)
 881→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
 882→
 883→        // Parse source silks to determine sequence
 884→        let (base, sequence) = jjrq_parse_silks_sequence(&source_heat.silks);
 885→        let seq = sequence.unwrap_or(1);
 886→
 887→        // Count actionable paces
 888→        let actionable_count = source_heat.order.iter().filter(|coronet_key| {
 889→            if let Some(pace) = source_heat.paces.get(*coronet_key) {
 890→                if let Some(tack) = pace.tacks.first() {
 891→                    matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled)
 892→                } else {
 893→                    false
 894→                }
 895→            } else {
 896→                false
 897→            }
 898→        }).count();
 899→
 900→        // Validate there are actionable paces to transfer
 901→        if actionable_count == 0 {
 902→            return Err(format!("Heat '{}' has no actionable paces to transfer", firemark_key));
 903→        }
 904→
 905→        // Count retained paces
 906→        let retained_count = source_heat.paces.len() - actionable_count;
 907→
 908→        // Count complete paces for steeplechase marker
 909→        let complete_count = source_heat.order.iter().filter(|coronet_key| {
 910→            if let Some(pace) = source_heat.paces.get(*coronet_key) {
 911→                if let Some(tack) = pace.tacks.first() {
 912→                    tack.state == jjrg_PaceState::Complete
 913→                } else {
 914→                    false
 915→                }
 916→            } else {
 917→                false
 918→            }
 919→        }).count();
 920→
 921→        // Create steeplechase marker entry
 922→        let marker_text = format!("Garlanded at pace {} — magnificent service", complete_count);
 923→
 924→        // Update source heat: add steeplechase marker (prepend to paddock file)
 925→        let source_paddock_path = base_path.join(&source_heat.paddock_file);
 926→        let existing_content = std::fs::read_to_string(&source_paddock_path)
 927→            .map_err(|e| format!("Failed to read paddock file: {}", e))?;
 928→
 929→        let updated_content = format!("{}\n\n{}", marker_text, existing_content);
 930→        std::fs::write(&source_paddock_path, updated_content)
 931→            .map_err(|e| format!("Failed to write paddock file: {}", e))?;
 932→
 933→        ((base, seq), source_heat.paddock_file.clone(), source_heat.order.clone(), actionable_count, retained_count)
 934→    };
 935→
 936→    // Build garlanded and continuation silks
 937→    let (base, seq) = source_silks;
 938→    let garlanded_silks = jjrq_build_garlanded_silks(&base, seq);
 939→    let continuation_silks = jjrq_build_continuation_silks(&base, seq + 1);
 940→
 941→    // Nominate new heat with continuation silks
 942→    let created_ts = jjrc_timestamp_from_env();
 943→    let nominate_args = jjrg_NominateArgs {
 944→        silks: continuation_silks.clone(),
 945→        created: created_ts,
 946→    };
 947→    let nominate_result = jjrg_nominate(gallops, nominate_args, base_path)?;
 948→    let new_firemark_key = nominate_result.firemark.clone();
 949→
 950→    // Get destination heat paddock file for copy
 951→    let dest_paddock_file = {
 952→        let dest_heat = gallops.heats.get(&new_firemark_key)
 953→            .ok_or_else(|| "Failed to retrieve newly nominated heat".to_string())?;
 954→        dest_heat.paddock_file.clone()
 955→    };
 956→
 957→    // Read original paddock content before modifications (for new heat)
 958→    let source_paddock_path = base_path.join(&source_paddock_file);
 959→    let original_paddock_content = std::fs::read_to_string(&source_paddock_path)
 960→        .map_err(|e| format!("Failed to read paddock file: {}", e))?;
 961→
 962→    // Extract original content (removing marker we just added)
 963→    let existing_content = original_paddock_content.split_once("\n\n")
 964→        .map(|(_, rest)| rest)
 965→        .unwrap_or(&original_paddock_content);
 966→
 967→    // Copy paddock content from source to new heat
 968→    let dest_paddock_path = base_path.join(&dest_paddock_file);
 969→    std::fs::write(&dest_paddock_path, existing_content)
 970→        .map_err(|e| format!("Failed to copy paddock to new heat: {}", e))?;
 971→
 972→    // Draft all actionable paces to new heat (in order)
 973→    for coronet_key in source_order {
 974→        if let Some(pace) = gallops.heats.get(&firemark_key).unwrap().paces.get(&coronet_key) {
 975→            if let Some(tack) = pace.tacks.first() {
 976→                if matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled) {
 977→                    // Draft this pace to new heat (append to end)
 978→                    let draft_args = jjrg_DraftArgs {
 979→                        coronet: coronet_key.clone(),
 980→                        to: new_firemark_key.clone(),
 981→                        before: None,
 982→                        after: None,
 983→                        first: false, // Append to end to maintain order
 984→                    };
 985→                    jjrg_draft(gallops, draft_args)?;
 986→                }
 987→            }
 988→        }
 989→    }
 990→
 991→    // Update source heat: change silks to garlanded, set status to stabled
 992→    let source_heat_mut = gallops.heats.get_mut(&firemark_key).unwrap();
 993→    source_heat_mut.silks = garlanded_silks.clone();
 994→    source_heat_mut.status = jjrg_HeatStatus::Stabled;
 995→
 996→    // Set new heat status to racing and move to front
 997→    let new_heat_mut = gallops.heats.get_mut(&new_firemark_key).unwrap();
 998→    new_heat_mut.status = jjrg_HeatStatus::Racing;
 999→    if let Some(heat_entry) = gallops.heats.shift_remove(&new_firemark_key) {
1000→        gallops.heats.shift_insert(0, new_firemark_key.clone(), heat_entry);
1001→    }
1002→
1003→    Ok(jjrg_GarlandResult {
1004→        old_firemark: firemark_key,
1005→        old_silks: garlanded_silks,
1006→        new_firemark: new_firemark_key,
1007→        new_silks: continuation_silks,
1008→        paces_transferred: actionable_count,
1009→        paces_retained: retained_count,
1010→    })
1011→}
1012→
1013→/// Restring - bulk draft multiple paces atomically
1014→///
1015→/// Moves multiple paces from source heat to destination heat in a single operation.
1016→/// All paces are validated before any mutations occur.
1017→/// Order is preserved in the destination heat.
1018→pub fn jjrg_restring(gallops: &mut jjrg_Gallops, args: jjrg_RestringArgs) -> Result<jjrg_RestringResult, String> {
1019→    // Parse and normalize firemarks
1020→    let source_firemark = Firemark::jjrf_parse(&args.source_firemark)
1021→        .map_err(|e| format!("Invalid source firemark: {}", e))?;
1022→    let source_firemark_key = source_firemark.jjrf_display();
1023→
1024→    let dest_firemark = Firemark::jjrf_parse(&args.dest_firemark)
1025→        .map_err(|e| format!("Invalid destination firemark: {}", e))?;
1026→    let dest_firemark_key = dest_firemark.jjrf_display();
1027→
1028→    // Validate firemarks are different
1029→    if source_firemark_key == dest_firemark_key {
1030→        return Err("Cannot draft paces to same heat".to_string());
1031→    }
1032→
1033→    // Validate both heats exist
1034→    if !gallops.heats.contains_key(&source_firemark_key) {
1035→        return Err(format!("Heat '{}' not found", source_firemark_key));
1036→    }
1037→    if !gallops.heats.contains_key(&dest_firemark_key) {
1038→        return Err(format!("Heat '{}' not found", dest_firemark_key));
1039→    }
1040→
1041→    // Validate coronet array is non-empty
1042→    if args.coronets.is_empty() {
1043→        return Err("No paces specified for draft".to_string());
1044→    }
1045→
1046→    // Validate all coronets before any mutations
1047→    let mut normalized_coronets = Vec::new();
1048→    for coronet_str in &args.coronets {
1049→        // Parse and normalize coronet
1050→        let coronet = Coronet::jjrf_parse(coronet_str)
1051→            .map_err(|e| format!("Invalid coronet '{}': {}", coronet_str, e))?;
1052→        let coronet_key = coronet.jjrf_display();
1053→
1054→        // Verify coronet belongs to source heat
1055→        let coronet_firemark = coronet.jjrf_parent_firemark();
1056→        if coronet_firemark.jjrf_display() != source_firemark_key {
1057→            return Err(format!(
1058→                "Pace {} does not belong to source heat {}",
1059→                coronet_key, source_firemark_key
1060→            ));
1061→        }
1062→
1063→        // Verify pace exists in source heat
1064→        let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
1065→        if !source_heat.paces.contains_key(&coronet_key) {
1066→            return Err(format!(
1067→                "Pace {} not found in heat {}",
1068→                coronet_key, source_firemark_key
1069→            ));
1070→        }
1071→
1072→        normalized_coronets.push(coronet_key);
1073→    }
1074→
1075→    // All validations passed - now perform the operations
1076→
1077→    // Capture source heat info before mutations
1078→    let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
1079→    let source_silks = source_heat.silks.clone();
1080→    let source_paddock = source_heat.paddock_file.clone();
1081→
1082→    // Capture destination heat info
1083→    let dest_heat = gallops.heats.get(&dest_firemark_key).unwrap();
1084→    let dest_silks = dest_heat.silks.clone();
1085→    let dest_paddock = dest_heat.paddock_file.clone();
1086→
1087→    // Draft each pace to destination (preserving order)
1088→    let mut mappings = Vec::new();
1089→    for coronet_key in normalized_coronets {
1090→        let draft_args = jjrg_DraftArgs {
1091→            coronet: coronet_key.clone(),
1092→            to: dest_firemark_key.clone(),
1093→            before: None,
1094→            after: None,
1095→            first: false, // Append to end to preserve order
1096→        };
1097→
1098→        // Get pace info before drafting (for output)
1099→        let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
1100→        let pace = source_heat.paces.get(&coronet_key).unwrap();
1101→        let first_tack = pace.tacks.first();
1102→        let silks = first_tack.map(|t| t.silks.clone()).unwrap_or_default();
1103→        let state = first_tack.map(|t| t.state.clone()).unwrap_or(jjrg_PaceState::Rough);
1104→        let spec_full = first_tack.map(|t| t.text.clone()).unwrap_or_default();
1105→        let spec_preview = if spec_full.len() > 80 {
1106→            format!("{}...", &spec_full[..77])
1107→        } else {
1108→            spec_full.clone()
1109→        };
1110→
1111→        // Perform the draft
1112→        let result = jjrg_draft(gallops, draft_args)?;
1113→
1114→        mappings.push(jjrg_RestringMapping {
1115→            old_coronet: coronet_key,
1116→            new_coronet: result.new_coronet,
1117→            silks,
1118→            state,
1119→            spec: spec_preview,
1120→        });
1121→    }
1122→
1123→    // Check if source heat is now empty
1124→    let source_heat_after = gallops.heats.get(&source_firemark_key).unwrap();
1125→    let source_empty_after = source_heat_after.paces.is_empty();
1126→
1127→    Ok(jjrg_RestringResult {
1128→        source_firemark: source_firemark_key,
1129→        source_silks,
1130→        source_paddock,
1131→        source_empty_after,
1132→        dest_firemark: dest_firemark_key,
1133→        dest_silks,
1134→        dest_paddock,
1135→        drafted: mappings,
1136→    })
1137→}
